import React, { ComponentType, ReactNode } from 'react';
import { ErrorBoundary } from 'react-error-boundary';

import { HighlighterProvider } from '@teambit/react.ui.highlighter-provider';
import { type ReactLiveComposition, needLiveControls, LivePreview } from '@bitdev/react.live-controls';
import { getDefaultControlsHook } from '@teambit/react.ui.mounter.use-default-controls';
import { getLiveControls } from '@teambit/react.modules.react-live-controls-from-schema';

// Prepare <AutoLiveControlsPreview /> to wrap <LivePreview />
// with auto controls feature.

const useDefaultControls = getDefaultControlsHook(getLiveControls);

function AutoLiveControlsPreview(props: ReactLiveComposition) {
  const resultProps = { ...props };
  const enabled = !resultProps.controls && !resultProps.noControls;
  const defaultControls = useDefaultControls(enabled);
  if (enabled && defaultControls.length) {
    resultProps.controls = defaultControls;
  }
  return (
    <LivePreview {...resultProps} />
  );
}

// TODO: remove when stable.
function activateLiveControls() {
  if (window.parent) {
    window.parent.postMessage({
      type: 'composition-live-controls:activate',
    }, '*');
  }
}
activateLiveControls();

/**
 * a reference to a provider function.
 */
export type MounterProvider = ComponentType<{ children: ReactNode }>;

type Root = { render: (element: React.ReactElement) => void; unmount: () => void };

// Both imports are dynamic so the bundler never statically validates named exports
// against whichever React version is installed.
// React 18/19: react-dom/client resolves → use createRoot.
// React 17:    react-dom/client rejects  → fall back to legacy ReactDOM.render.
let createRootImpl: ((container: HTMLElement) => Root) | null = null;
import('react-dom/client')
  .then((m: any) => {
    createRootImpl = (container) => m.createRoot(container);
  })
  .catch(() => {
    import('react-dom').then((m: any) => {
      createRootImpl = (container): Root => ({
        render: (element) => m.render(element, container),
        unmount: () => m.unmountComponentAtNode(container),
      });
    });
  });

function createCompatRoot(container: HTMLElement): Root {
  if (createRootImpl) return createRootImpl(container);
  throw new Error('[react-compat] createCompatRoot called before module init settled');
}

/**
 * a reference to a root instance.
 */
let root: Root | null = null;
/**
 * a reference to the root document.
 */
let rootDoc: HTMLElement | null = null;

/**
 * create a mounter.
 */
export function createMounter(Provider: MounterProvider = React.Fragment): any {
  return (Composition: React.ComponentType | ReactLiveComposition) => {
    const isLiveComposition = typeof Composition === 'object';

    if (isLiveComposition && !needLiveControls(window.location)) {
      // eslint-disable-next-line no-param-reassign
      Composition.noControls = true;
    }

    if (root && rootDoc) {
      // Unmount the existing root before mounting a new one.
      root.unmount();
      root = null;
      rootDoc = null;
    }

    rootDoc = document.getElementById('root');
    root = createCompatRoot(rootDoc!);
    
    root.render(
      // @ts-ignore TODO: remove this after release.
      <ErrorBoundary fallback={<></>}>
        {/* @ts-ignore TODO: need a react18 HighlighterProvider to fix this */}
        <HighlighterProvider>
          <Provider>
            {isLiveComposition ? (
              <AutoLiveControlsPreview {...Composition} />
            ) : (
              <Composition />
            )}
          </Provider>
        </HighlighterProvider>
      </ErrorBoundary>
    );
  };
}

export default createMounter;
